const STRIPE_PUBLISHABLE_KEY = 'pk_test_YOUR_STRIPE_PUBLISHABLE_KEY'; // Replace with your actual Stripe publishable key
const BACKEND_URL = 'https://your-secure-backend.com'; // Your secure backend for processing payments

const PRODUCT_SKUS_IOS = ['com.yourapp.premium_monthly', 'com.yourapp.coin_pack_small']; // Your iOS IAP product IDs
const PRODUCT_SKUS_ANDROID = ['com.yourapp.premium_monthly', 'com.yourapp.coin_pack_small']; // Your Android IAP product IDs

class PaymentManager {
  static instance = null;
  iapProducts = [];
  iapSubscriptions = [];
  purchaseUpdateListener = null;
  purchaseErrorListener = null;

  constructor() {
    if (PaymentManager.instance) {
      return PaymentManager.instance;
    }
    PaymentManager.instance = this;
  }

  async initializeIAP() {
    try {
      await RNIap.initConnection();
      if (Platform.OS === 'android') {
        await RNIap.flushFailedPurchasesCachedAsPendingAndroid();
      }
      this._addIAPListeners();
      await this.getIAPProducts();
      return true;
    } catch (err) {
      console.warn('IAP Initialization Error:', err.code, err.message);
      Alert.alert('IAP Error', 'Could not connect to app store billing. Please try again later.');
      return false;
    }
  }

  _addIAPListeners() {
    this.purchaseUpdateListener = RNIap.purchaseUpdatedListener(async (purchase) => {
      const receipt = purchase.transactionReceipt;
      if (receipt) {
        try {
          // IMPORTANT: Validate receipt on your secure backend! Do NOT trust client-side receipts.
          const response = await fetch(`${BACKEND_URL}/verify-iap-receipt`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              receipt: receipt,
              productId: purchase.productId,
              platform: Platform.OS,
              transactionId: purchase.transactionId,
            }),
          });
          const result = await response.json();

          if (response.ok && result.success) {
            await finishTransaction(purchase);
            Alert.alert('Purchase Successful', 'Your purchase has been processed!');
            // TODO: Grant user entitlement, update UI, etc.
          } else {
            Alert.alert('Purchase Failed', result.message || 'Receipt validation failed.');
            // For server-side validation failures, generally finish the transaction
            // as the client side has done its part. The user won't get the product.
            await finishTransaction(purchase);
          }
        } catch (error) {
          console.error('Receipt verification or transaction finishing error:', error);
          Alert.alert('Purchase Error', 'Failed to verify your purchase. Please contact support.');
          // If network or internal error, do NOT finish transaction here; allow user to retry verification
          // or manual check by support.
        }
      }
    });

    this.purchaseErrorListener = RNIap.purchaseErrorListener((error) => {
      console.log('IAP purchase error:', error.code, error.message);
      if (!(error.code === 'E_USER_CANCELLED' || error.code === 'E_DISMISSED')) {
        Alert.alert('Purchase Error', error.message);
      }
    });
  }

  _removeIAPListeners() {
    if (this.purchaseUpdateListener) {
      this.purchaseUpdateListener.remove();
      this.purchaseUpdateListener = null;
    }
    if (this.purchaseErrorListener) {
      this.purchaseErrorListener.remove();
      this.purchaseErrorListener = null;
    }
  }

  async endIAPConnection() {
    try {
      this._removeIAPListeners();
      await RNIap.endConnection();
      return true;
    } catch (err) {
      console.warn('Error ending IAP connection:', err);
      return false;
    }
  }

  async getIAPProducts() {
    try {
      const productIds = Platform.select({
        ios: PRODUCT_SKUS_IOS,
        android: PRODUCT_SKUS_ANDROID,
      });
      const products = await getProducts(productIds);
      this.iapProducts = products.filter(p => p.type === 'product');
      this.iapSubscriptions = products.filter(p => p.type === 'subscription');
      return { products: this.iapProducts, subscriptions: this.iapSubscriptions };
    } catch (err) {
      console.warn('Error fetching IAP products:', err);
      Alert.alert('IAP Error', 'Could not load in-app products. Please check your network.');
      return { products: [], subscriptions: [] };
    }
  }

  async purchaseProduct(productId) {
    try {
      await requestPurchase(productId);
      // PurchaseUpdatedListener will handle the actual transaction finishing and verification
    } catch (err) {
      console.warn('IAP purchase request error:', err.code, err.message);
      if (!(err.code === 'E_USER_CANCELLED' || err.code === 'E_DISMISSED')) {
        Alert.alert('Purchase Failed', err.message);
      }
    }
  }

  async purchaseSubscription(productId) {
    try {
      await requestSubscription(productId);
      // PurchaseUpdatedListener will handle the actual transaction finishing and verification
    } catch (err) {
      console.warn('IAP subscription request error:', err.code, err.message);
      if (!(err.code === 'E_USER_CANCELLED' || err.code === 'E_DISMISSED')) {
        Alert.alert('Subscription Failed', err.message);
      }
    }
  }

  async restorePurchases() {
    try {
      const purchases = await getAvailablePurchases();
      if (purchases.length === 0) {
        Alert.alert('No Purchases', 'No previous purchases found to restore.');
        return [];
      }
      for (const purchase of purchases) {
        const receipt = purchase.transactionReceipt;
        if (receipt) {
          // Send to backend for verification and entitlement granting for restored purchases
          // await fetch(`${BACKEND_URL}/verify-iap-receipt`, ...)
          console.log(`Restored purchase for product: ${purchase.productId}. Receipt: ${receipt}`);
        }
      }
      Alert.alert('Purchases Restored', `Found ${purchases.length} previous purchases.`);
      return purchases;
    } catch (err) {
      console.warn('Error restoring purchases:', err);
      Alert.alert('Restore Failed', 'Could not restore purchases. Please try again.');
      return [];
    }
  }

  // Stripe backend interaction to create PaymentIntent
  async createStripePaymentIntent(amount, currency = 'usd', description = 'Purchase from app') {
    try {
      const response = await fetch(`${BACKEND_URL}/create-payment-intent`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ amount, currency, description }),
      });
      const data = await response.json();

      if (!response.ok || data.error) {
        console.error('Backend error creating PaymentIntent:', data.error);
        return { success: false, error: data.error || 'Failed to create payment intent on server.' };
      }
      return { success: true, ...data }; // Expected: clientSecret, customerId, ephemeralKey
    } catch (error) {
      console.error('Network error creating PaymentIntent:', error);
      return { success: false, error: 'Network error or server unavailable.' };
    }
  }

  // Placeholder for other digital wallet integrations
  async processPayPalTransaction(amount, currency, description) {
    Alert.alert('Not Implemented', 'PayPal payments are not yet supported. Integration requires PayPal SDK and backend.');
    return { success: false, message: 'Not implemented' };
  }

  dispose() {
    this.endIAPConnection();
  }
}

// StripeProvider should wrap the root of your application or the component tree where Stripe payments are initiated.
const StripePaymentWrapper = ({ children }) => (
  <StripeProvider
    publishableKey={STRIPE_PUBLISHABLE_KEY}
    merchantIdentifier="merchant.com.your_app_name" // Required for Apple Pay
  >
    {children}
  </StripeProvider>
);

const paymentManager = new PaymentManager();

const PaymentScreen = () => {
  const [iapReady, setIapReady] = useState(false);
  const [products, setProducts] = useState([]);
  const [subscriptions, setSubscriptions] = useState([]);
  const { initPaymentSheet, presentPaymentSheet, loading } = useStripe();

  useEffect(() => {
    const init = async () => {
      const success = await paymentManager.initializeIAP();
      setIapReady(success);
      if (success) {
        const { products: fetchedProducts, subscriptions: fetchedSubscriptions } = await paymentManager.getIAPProducts();
        setProducts(fetchedProducts);
        setSubscriptions(fetchedSubscriptions);
      }
    };
    init();

    return () => {
      paymentManager.dispose();
    };
  }, []);

  const handleIAPPurchase = async (productId, isSubscription) => {
    if (!iapReady) {
      Alert.alert('Error', 'In-app purchases not ready.');
      return;
    }
    if (isSubscription) {
      await paymentManager.purchaseSubscription(productId);
    } else {
      await paymentManager.purchaseProduct(productId);
    }
  };

  const handleStripePayment = async () => {
    const amount = 1000; // Example: $10.00 in cents
    const currency = 'usd';
    const description = 'Premium Service';

    const backendResponse = await paymentManager.createStripePaymentIntent(amount, currency, description);

    if (!backendResponse.success) {
      Alert.alert('Payment Error', backendResponse.error || 'Failed to prepare Stripe payment.');
      return;
    }

    const { clientSecret, customerId, ephemeralKey } = backendResponse;

    const { error: initError } = await initPaymentSheet({
      merchantDisplayName: 'Your App Name',
      customerId: customerId,
      customerEphemeralKeySecret: ephemeralKey,
      paymentIntentClientSecret: clientSecret,
      allowsDelayedPaymentMethods: true,
      // For Apple Pay/Google Pay via Stripe, ensure your Stripe Dashboard has these configured
      // and you've added the necessary entitlements/permissions to your native project.
    });

    if (initError) {
      Alert.alert('Payment Setup Failed', initError.message);
      return;
    }

    const { error: presentError } = await presentPaymentSheet();

    if (presentError) {
      if (presentError.code === 'Canceled') {
        Alert.alert('Payment Canceled', 'You cancelled the payment process.');
      } else {
        Alert.alert('Payment Failed', presentError.message);
      }
    } else {
      Alert.alert('Payment Successful', 'Your payment has been processed!');
      // TODO: Update UI or navigate upon successful payment
    }
  };

  return (
    <ScrollView style={styles.container}>
      <Text style={styles.header}>In-App Purchases (IAP)</Text>
      {!iapReady && <Text style={styles.statusText}>Initializing IAP...</Text>}
      {products.length > 0 && (
        <View style={styles.section}>
          <Text style={styles.subheader}>Available Products:</Text>
          {products.map((product) => (
            <View key={product.productId} style={styles.item}>
              <Text>{product.title} ({product.localizedPrice})</Text>
              <Button title="Buy" onPress={() => handleIAPPurchase(product.productId, false)} />
            </View>
          ))}
        </View>
      )}

      {subscriptions.length > 0 && (
        <View style={styles.section}>
          <Text style={styles.subheader}>Available Subscriptions:</Text>
          {subscriptions.map((sub) => (
            <View key={sub.productId} style={styles.item}>
              <Text>{sub.title} ({sub.localizedPrice})</Text>
              <Button title="Subscribe" onPress={() => handleIAPPurchase(sub.productId, true)} />
            </View>
          ))}
        </View>
      )}

      <Button
        title="Restore Purchases"
        onPress={() => paymentManager.restorePurchases()}
        disabled={!iapReady}
      />

      <Text style={[styles.header, { marginTop: 20 }]}>Digital Wallet / Credit Card (Stripe)</Text>
      <Button
        title="Pay with Stripe"
        onPress={handleStripePayment}
        disabled={loading} // `loading` from useStripe indicates if payment sheet is busy
      />

      <Text style={[styles.header, { marginTop: 20 }]}>Other Payment Methods</Text>
      <Button
        title="Pay with PayPal (Not Implemented)"
        onPress={() => paymentManager.processPayPalTransaction(10, 'usd', 'Example Item')}
      />
    </ScrollView>
  );
};

